  'en',
  '{"common":{"siteName":"Karen Zhu","baseTitle":"Karen Zhu","nav":[{"label":"Marketing","path":"specialties"},{"label":"About Me","path":"about"}],"languageLabel":"Language","languages":{"en":"English","fr":"Français"},"toggleNavMenu":"Toggle navigation menu","footer":"© 2026 by Karen Zhu | Social Media Marketing","showcases":[{"title":"Bun and Bread Club","subtitle":"A cozy café experience designed from concept to reality","cta_label":"View More","cta_url":"https://www.bunandbreadclub.com/","carouselImages":[{"imageSrc":"/img/{person_id}/showcase1_carousel_1.jpg","imageAlt":"Bun and Bread Club exterior view"},{"imageSrc":"/img/{person_id}/showcase1_carousel_2.jpg","imageAlt":"Bun and Bread Club interior seating area"},{"imageSrc":"/img/{person_id}/showcase1_carousel_3.jpg","imageAlt":"Bun and Bread Club menu showcase"}],"features":[{"title":"Brand Identity","description":"Created a warm, inviting brand identity with a cohesive color palette and logo design that reflects the café''s values of comfort and community. The design emphasizes the artisanal nature of fresh baked goods."},{"title":"Interior Design","description":"Collaborated on the café''s interior layout and aesthetic, ensuring the space promotes a welcoming atmosphere for customers to relax and enjoy their experience."},{"title":"Marketing Materials","description":"Designed comprehensive marketing collateral including business cards, flyers, and social media graphics to launch the café and build initial brand awareness in the local community."},{"title":"Social Media Strategy","description":"Developed and executed a social media marketing strategy to grow the café''s online presence and engage with customers through regular posts and community interactions."}],"stories":[{"title":"From Concept to Launch","subtitle":"The Journey of Bringing Bun and Bread Club to Life","description":"Working on this project was incredibly rewarding as I got to see the café grow from an idea into a thriving business. The owners had a clear vision but needed help translating it into visual designs and marketing strategy.","images":[{"imageSrc":"/img/{person_id}/showcase1_carousel_1.jpg","imageAlt":"Initial sketches and brainstorming session"},{"imageSrc":"/img/{person_id}/showcase1_carousel_2.jpg","imageAlt":"Final design mockups and brand guidelines"}],"footer":"This experience taught me the importance of understanding the client''s vision and translating it into practical, beautiful design solutions that resonate with their target audience."}]},{"title":"Bun and Bread Club","subtitle":"A cozy café experience designed from concept to reality","cta_label":"View More","cta_url":"https://www.bunandbreadclub.com/","carouselImages":[{"imageSrc":"/img/{person_id}/showcase1_carousel_1.jpg","imageAlt":"Bun and Bread Club exterior view"},{"imageSrc":"/img/{person_id}/showcase1_carousel_2.jpg","imageAlt":"Bun and Bread Club interior seating area"},{"imageSrc":"/img/{person_id}/showcase1_carousel_3.jpg","imageAlt":"Bun and Bread Club menu showcase"}],"features":[{"title":"Brand Identity","description":"Created a warm, inviting brand identity with a cohesive color palette and logo design that reflects the café''s values of comfort and community. The design emphasizes the artisanal nature of fresh baked goods."},{"title":"Interior Design","description":"Collaborated on the café''s interior layout and aesthetic, ensuring the space promotes a welcoming atmosphere for customers to relax and enjoy their experience."},{"title":"Marketing Materials","description":"Designed comprehensive marketing collateral including business cards, flyers, and social media graphics to launch the café and build initial brand awareness in the local community."},{"title":"Social Media Strategy","description":"Developed and executed a social media marketing strategy to grow the café''s online presence and engage with customers through regular posts and community interactions."}],"stories":[{"title":"From Concept to Launch","subtitle":"The Journey of Bringing Bun and Bread Club to Life","description":"Working on this project was incredibly rewarding as I got to see the café grow from an idea into a thriving business. The owners had a clear vision but needed help translating it into visual designs and marketing strategy.","images":[{"imageSrc":"/img/{person_id}/showcase1_carousel_1.jpg","imageAlt":"Initial sketches and brainstorming session"},{"imageSrc":"/img/{person_id}/showcase1_carousel_2.jpg","imageAlt":"Final design mockups and brand guidelines"}],"footer":"This experience taught me the importance of understanding the client''s vision and translating it into practical, beautiful design solutions that resonate with their target audience."}]}]},"theme":{"fontFamily":"Poppins"},"home":{"hero":{"title":"Karen Zhu","subtitle":"Student | Designer | Marketer | Artist","intro":"A third year <color:#7fb685>business student</color> with a <color:#7fb685>passion for art and design</color>, interested in finding innovative solutions to <color:#7fb685>complex problems</color>! Welcome to my creative portfolio with samples of UX design work, website design, digital marketing, and passion projects!"},"features":{"title":"Explore My Interests","items":[{"icon":"/img/{person_id}/interest_about.avif","title":"About Me","path":"about"},{"icon":"/img/{person_id}/interest_marketing.avif","title":"Social Media Marketing","path":"specialties"},{"icon":"/img/{person_id}/interest_design.avif","title":"Design","path":"engagements#engagement-0"},{"icon":"/img/{person_id}/interest_art.avif","title":"Art","path":"engagements#engagement-0"},{"icon":"/img/{person_id}/interest_photography.avif","title":"Photography","path":"engagements#engagement-0"}]},"topEngagements":[{"heading":"Cherish Integrated Services","title":"Event and Donations Website Design","cta_label":"Learn More","cta_path":"cherish","image":"/img/{person_id}/engagement_cherish.avif"},{"heading":"Rotman Commerce Fashion Group","title":"Director of Creative Content","cta_label":"Learn More","cta_path":"engagements#engagement-0","image":"/img/{person_id}/engagement_rcfg.avif"},{"heading":"RCIG x RCFTA Design Dash Finalist","title":"App Design for Financial Meal Budgeting","cta_label":"Learn More","cta_path":"simonSaves","image":"/img/{person_id}/engagement_simonSaves.avif"}]},"about":{"pageTitle":"About Me | Karen Zhu","title":"Karen Zhu","subtitle":"About Me","avatarAlt":"Personal character illustration","avatarSrc":"/img/{person_id}/Personal-Character.avif","hobbiesImageSrc":"/img/{person_id}/aboutMe_hobbies.png","aboutParagraphs":["I''m a business student with a strong passion for design. Growing up taking art classes, I always enjoyed expressing my creativity in visual forms and found that I had a talent for it.","I decided to pursue business as a degree because of the flexibility of being able to mould my interests with work and school. Like art, business requires thoughtful solutions that are both creative and practical. In my first year of classes at the University of Toronto, I particularly enjoyed my marketing classes because they heavily involved a creative components and offer opportunities to expand into design.","To further explore this area of interest, in July of 2024, I completed the Google UX Design course and learned how to develop wireframes and mockups on Figma. Furthermore, I placed in the final of the 2024 Design Dash competition hosted by Rotman Commerce by applying these skills. This experience revealed a strong interest to continue pursuing creative opportunities as I not only enjoyed them, but had a talent for it.","I strive to use design and business strategy to create innovative and accessible user experiences. Please reach out to learn a bit more about me!"],"funFactsTitle":"Some Fun Facts","funFacts":["I enjoy making different cafe style drinks! My favourites: matcha lattes, lavender london fogs, Hong Kong style milk tea, yuzu tea. I like visiting local cafes and rating their drinks for inspiration.","I have a passion for fashion - it''s another creative form of expression and I believe in dressing for success. I also admire creative marketing in the fashion industry."]},"engagements":{"items":[{"pageTitle":"Engagements | Karen Zhu","logoSrc":"/img/{person_id}/RCFG logo.avif","logoAlt":"RCFG logo","title":"Rotman Commerce Fashion Group","taglineFirst":"Creative Minds,","taglineSecond":"Fashioned Together","cards":[{"id":"about","title":"About","logoSrc":"","bodyLines":["A fashion business club run by University of Toronto students that revolves around core values of education, community, and networking in the fashion industry. The purpose of RCFG is to provide Rotman Commerce students the opportunity to connect on fashion and beauty topics such as global trends, styling advice, fashion careers, and business fashion.","We host engaging events and create community within the world of fashion.","Join us to expand your network and passion for the industry."]},{"id":"journey","title":"My Journey","logoSrc":"","bodyLines":["Director of Creative Content Feb 2024 - Present","Manager of Creative Content Feb 2023 - Feb 2024"]},{"id":"impact","title":"Impact","logoSrc":"","bodyLines":["450+ student event attendees","10,000+ engaged audiences","1,140 Instagram Followers"]},{"id":"connect","title":"Connect with Us","logoSrc":"","bodyLines":[],"isConnectCard":true,"links":[{"label":"Instagram","handle":"@rcfashiongroup","url":"https://www.instagram.com/rcfashiongroup"},{"label":"","handle":"www.rcfashiongroup.com","url":"https://www.rcfashiongroup.com"}]}],"artworkHeading":"Merch Design","artworkBody":"The Creative Content team was responsible for designing artwork for this year''s team. Below are some rough ideas and iterations upon receiving feedback:","artworkImageAlts":["karen - 1 (1).png","karen - 2 (1).png","Untitled50_20240716182107.png"],"artworkImageSrcs":["/img/{person_id}/karen-1-1.avif","/img/{person_id}/karen-2-1.avif","/img/{person_id}/Untitled50_20240716182107.avif"],"creativePostsHeading":"Creative Posts","creativePostsIntro":"Our team thinks of creative ways to promote club events and, when there are no upcoming events, executes large creative projects such as street interviews and Instagram takeovers to keep our audience entertained and maintain consistent uploads.","events":[{"heading":"RCFG Thrift Finds","stats":"This September, to promote our Thrifting in Toronto event, we created a scrapbook style post to showcase executive team thrift finds.","statsLines":["759 Accounts Reached","85.7% from followers","14.3% from non-followers"],"imageAlt":"Exec Thrift Finds Cover","imageSrc":"/img/{person_id}/ExecThriftFinds.avif"}],"creativeReelsHeading":"Creative Reels","creativeReelsBody":"Event Recaps, Day in the Life, and more coming soon...","showcases":[{"heading":"Director of Creative Content","subtitle":"Feb. 2024 - Present","cards":[{"title":"Leadership","description":"Directed a group of 5 committee members to increase engagement and maximize event attendance."},{"title":"Coordination","description":"Worked closely with Marketing Directors to organize a content calendar and upload schedule."},{"title":"Execusion","description":"Encouraged idea generation and delegated tasks to committee members based on their strengths."},{"title":"Market Analysis","description":"Kept up with Instagram/TikTok trends and executed creative fashion content posts."}]}]}]},"specialties":{"pageTitle":"Social Media Marketing | Karen Zhu","title":"Social Media Marketing","sectionTitle":"Leadership Roles","intro":"Through my student leadership roles, I created promotional graphics and reels to promote events and increase engagement.","roles":[{"title":"Director of Creative Content","organization":"Rotman Commerce Fashion Group","duration":"(2024 - 2025)","imageSrc":"/img/{person_id}/RCFG-headers.avif","imageAlt":"Director of Creative Content - Rotman Commerce Fashion Group","link":"engagements#engagement-0"},{"title":"Director of Marketing & Design","organization":"UofT Finance & Leadership Council","duration":"(2025 - 2026)","imageSrc":"/img/{person_id}/FLC-headers.avif","imageAlt":"Director of Marketing & Design - UofT Finance & Leadership Council"}]},"cherish":{"browserTabName":"Cherish Integrated Services - Karen Zhu","hero":{"title":"Cherish Integrated Services","subtitle":"Designing a Charity Event Website and Donation Platform","cta_label":"Visit Site","cta_url":"https://cherish-love-gala-2024.raiselysite.com/"},"organization":{"heading":"Organization Background","body":["Cherish Integrated Services (CHIS) is a non-profit organization and registered charity that serves individuals with developmental disabilities in the Greater Toronto Area. They offer a variety of programs for each age group to aid in vocational training, job venture, and or daily living.","CHIS hosts an annual Love Gala to raise funds to further expand their services and facilities. This year, proceeds will go towards developping their new Vocational Training Centre. This new facility will help more developped trainees work in a real cafe environemnt and learn employable skills."]},"role":{"heading":"My Role","title":"Digital Marketing Coordinator","dates":"Jun 2024 - Aug 2024","body":["As the sole designer during my term, I developped an website for the 2024 Cherish Love Gala charity event using the platform Raisley. I ensured to include important details regarding the event and managed incoming donations and ticket sales.","In addition to the design aspect, I heavily participated in developping the sponsorship package and communicating with local businesses and media outlets in regards to the event."]},"features":{"centerVideo":"/img/{person_id}/cherish_demo.mp4","centerVideoPoster":"/img/{person_id}/cherish_features.avif","centerVideoAlt":"Cherish Love Gala website demo","leftItems":[{"title":"Performer Profiles","description":"Creating an introductory and donation page for each performer where supporters can pledge their donations to."},{"title":"Ticket Sales & Donations","description":"Linking Powr.io for ticket sales and food cost deductions in tax receipts."}],"rightItems":[{"title":"Event Details","description":"Informing guests on the location, date, time, and ticket inclusions. Describing the cause in which all proceeds will go towards."},{"title":"Sponsors","description":"List all supporters, event sponsors, and prize (raffle and silent auction) sponsors in the footer with linkbacks to their website."}]},"gallery":{"leftImage":{"src":"/img/{person_id}/cherish_performers.avif","alt":"Love Gala Performers page screenshot"},"middleImages":[{"src":"/img/{person_id}/cherish_donation.avif","alt":"Pledge donation page screenshot"},{"src":"/img/{person_id}/cherish_donation2.avif","alt":"Pledge donation page screenshot2"}],"rightImage":{"src":"/img/{person_id}/cherish_about.avif","alt":"What is Cherish Love Gala page screenshot"}}},"simonSaves":{"browserTabName":"SimonSaves - Karen Zhu","hero":{"title":"SimonSaves","subtitle":"Rotman Commerce Innovation Group x Rotman Commerce Fintech Association Design Dash Finalist","cta_label":"View Prototype","cta_url":"https://www.figma.com/proto/xw4hyc3g8zxUA3be71XRB2/Recipe-Book-App-Prototype?type=design&node-id=1-2&t=hYJdCZQe1uISo0eg-1&scaling=scale-down&page-id=0%3A1&starting-point-node-id=180%3A223"},"overview":{"heading":"Overview","body":["Our group of 4 placed in the Top 3 for a case competition that challenged us to design a solution to solve an issue in the financial technology sector. Our solution introduced an app that uses machine learning to recommend recipes and spending on meals based on users'' budgets and dietary restrictions and preferences."]},"keyFeatures":{"title":"Key Features","items":["Filtered recipe and grocery search based on dietary restrictions and recommendations","Financial food budgeting summary on homepage","Information Cards providing tips and facts on different ingredients","Online community to chat with other app users and ask questions","Scrolling advertisement banners on homepage to promote ongoing discounts and sales"]},"role":{"heading":"My Role","title":"UX Designer and Logo Creator","dates":"2023","body":["Due to my experience using Figma through Google''s online UX Design course, with another team member, we took on the task of developing a user friendly app for financial budgeting and food education. The diverse skills of our team enabled me to lead the design process and guide my team mate through the basic functions of Figma.","Together, we worked on paper wireframes to brainstorm ideas, followed by creating mockups for each page on the app. I then took on the sole responsibility of the prototype stage, ensuring seamless interactions for all buttons.","Because of my extensive visual arts background, I also took on the task of creating a personalized mascot and logo for our brand. Our intended brand image was educational and friendly, thus leading to the creation of Simon the Persimmon. As a group, we decided on the name as we believed that consumers would immediately associate the unique fruit to our brand because of its rhyming name and uncommon use."]},"results":{"heading":"Results","body":["Our group made it to the final presentation round where we got the opportunity to pitch our idea to a panel of experienced UX and Product designers. The final presentation included 10 minutes for pitch delivery and 5 minutes for panelists'' questions."]},"learnings":{"title":"Learnings","items":["The Design Process is a continual cycle","Background knowledge in technology is crucial","Utilize diverse team member skills with task delegation, but ensure all members have a say in each aspect of the project to maximize potential"]},"gallery":{"mainImage":{"src":"/img/{person_id}/SimonSaves_Mockup.avif","alt":"SimonSaves app mockup screenshot"},"mascotImage":{"src":"/img/{person_id}/SimonSaves_Logo.avif","alt":"Simon the Persimmon mascot logo"}}}}',
  NOW()
)
ON CONFLICT ("PortfolioId", "Language") DO NOTHING;

