  '{"common":{"siteName":"Karen Zhu","baseTitle":"Karen Zhu","nav":[{"label":"Marketing","path":"specialties"},{"label":"À Propos de Moi","path":"about"}],"languageLabel":"Langue","languages":{"en":"English","fr":"Français"},"toggleNavMenu":"Basculer le menu de navigation","footer":"© 2026 Karen Zhu | Marketing des médias sociaux","showcases":[{"title":"Club du Pain et des Petits Pains","subtitle":"Une expérience confortable de café conçue du concept à la réalité","cta_label":"Voir Plus","cta_url":"https://example.com","carouselImages":[{"imageSrc":"/img/{person_id}/showcase1_carousel_1.png","imageAlt":"Vue extérieure du Club du Pain et des Petits Pains"},{"imageSrc":"/img/{person_id}/showcase1_carousel_2.png","imageAlt":"Zone de sièges intérieures du Club du Pain et des Petits Pains"},{"imageSrc":"/img/{person_id}/showcase1_carousel_3.png","imageAlt":"Présentation du menu du Club du Pain et des Petits Pains"}],"features":[{"title":"Identité de Marque","description":"J''ai créé une identité de marque chaleureuse et accueillante avec une palette de couleurs cohérente et un logo qui reflète les valeurs du café de confort et de communauté. Le design souligne la nature artisanale des produits de boulangerie frais."},{"title":"Design d''Intérieur","description":"J''ai collaboré sur la mise en page intérieure du café et l''esthétique, en veillant à ce que l''espace favorise une atmosphère accueillante pour que les clients se détendent et apprécient leur expérience."},{"title":"Matériel de Marketing","description":"J''ai conçu des supports marketing complets incluant des cartes de visite, des dépliants et des graphiques de réseaux sociaux pour lancer le café et construire une notoriété de marque initiale dans la communauté locale."},{"title":"Stratégie Réseaux Sociaux","description":"J''ai développé et exécuté une stratégie de marketing sur les réseaux sociaux pour développer la présence en ligne du café et s''engager avec les clients grâce à des publications régulières et des interactions communautaires."}],"stories":[{"title":"Du Concept au Lancement","subtitle":"Le Parcours de la Création du Club du Pain et des Petits Pains","description":"Travailler sur ce projet a été incroyablement gratifiant car j''ai pu voir le café se transformer d''une idée en une entreprise prospère. Les propriétaires avaient une vision claire mais avaient besoin d''aide pour la traduire en designs visuels et en stratégie marketing.","images":[{"imageSrc":"/img/{person_id}/showcase1_story1_1.png","imageAlt":"Croquis initiaux et session de brainstorming"},{"imageSrc":"/img/{person_id}/showcase1_story1_2.png","imageAlt":"Maquettes de conception finales et directives de marque"}],"footer":"Cette expérience m''a enseigné l''importance de comprendre la vision du client et de la traduire en solutions de conception pratiques et belles qui résonnent avec leur public cible."}]}]},"theme":{"fontFamily":"Poppins"},"home":{"hero":{"title":"Karen Zhu","subtitle":"Étudiante | Designer | Marketeur | Artiste","intro":"Une étudiante en commerce de troisième année avec une <color:#7fb685>passion pour l''art et le design</color>, intéressée à trouver des solutions innovantes à des <color:#7fb685>problèmes complexes</color>! Bienvenue sur mon portfolio créatif avec des échantillons de travaux de conception UX, de conception de sites Web, de marketing numérique et de projets personnels!"},"features":{"title":"Explorez mes intérêts","items":[{"icon":"/img/{person_id}/interest_about.avif","title":"À propos de moi","path":"about"},{"icon":"/img/{person_id}/interest_marketing.avif","title":"Marketing des médias sociaux","path":"specialties"},{"icon":"/img/{person_id}/interest_design.avif","title":"Design","path":"engagements#engagement-0"},{"icon":"/img/{person_id}/interest_art.avif","title":"Art","path":"engagements#engagement-0"},{"icon":"/img/{person_id}/interest_photography.avif","title":"Photographie","path":"engagements#engagement-0"}]},"topEngagements":[{"heading":"Services intégrés Cherish","title":"Conception de site Web pour événements et dons","cta_label":"En savoir plus","cta_path":"cherish","image":"/img/{person_id}/engagement_cherish.avif"},{"heading":"Rotman Commerce Fashion Group","title":"Directrice de contenu créatif","cta_label":"En savoir plus","cta_path":"engagements#engagement-0","image":"/img/{person_id}/engagement_rcfg.avif"},{"heading":"Finaliste RCIG x RCFTA Design Dash","title":"Conception d''application pour la budgétisation des repas","cta_label":"En savoir plus","cta_path":"simonSaves","image":"/img/{person_id}/engagement_simonSaves.avif"}]},"about":{"pageTitle":"À propos | Karen Zhu","title":"Karen Zhu","subtitle":"À propos de moi","avatarAlt":"Illustration de personnage personnel","avatarSrc":"/img/{person_id}/Personal-Character.avif","hobbiesImageSrc":"/img/{person_id}/aboutMe_hobbies.png","aboutParagraphs":["Je suis étudiante en commerce avec une forte passion pour le design. En grandissant en prenant des cours d''art, j''ai toujours apprécié exprimer ma créativité sous des formes visuelles et j''ai trouvé que j''avais un talent pour cela.","J''ai décidé de poursuivre les affaires comme diplôme en raison de la flexibilité pour façonner mes intérêts avec le travail et l''école. Comme l''art, les affaires exigent des solutions réfléchies qui sont à la fois créatives et pratiques. Dans ma première année de cours à l''Université de Toronto, j''ai particulièrement apprécié mes cours de marketing car ils impliquaient fortement des composants créatifs et offrent des opportunités d''expansion dans le design.","Pour explorer davantage cet intérêt, en juillet 2024, j''ai terminé le cours Google UX Design et j''ai appris à développer des wireframes et des maquettes sur Figma. De plus, j''ai terminé dans la finale de la compétition Design Dash 2024 organisée par Rotman Commerce en appliquant ces compétences. Cette expérience a révélé un fort intérêt à continuer à poursuivre des opportunités créatives car non seulement je les aimais, mais j''avais aussi un talent pour cela.","Je m''efforce d''utiliser le design et la stratégie commerciale pour créer des expériences utilisateur innovantes et accessibles. Veuillez me contacter pour en savoir plus sur moi !"],"funFactsTitle":"Quelques faits amusants","funFacts":["J''aime faire différentes boissons de style café ! Mes préférées : lattes au matcha, brouillards londoniens à la lavande, thé au lait de Hong Kong, thé au yuzu. J''aime visiter les cafés locaux et noter leurs boissons spéciales pour m''inspirer.","J''ai une passion pour la mode - c''est une autre forme d''expression créative et je crois en m''habiller pour réussir. J''admire aussi le marketing créatif de l''industrie de la mode."]},"engagements":{"items":[{"pageTitle":"Engagements | Karen Zhu","logoSrc":"/img/{person_id}/RCFG logo.avif","logoAlt":"Logo RCFG","title":"Groupe de mode Rotman Commerce","taglineFirst":"Des esprits créatifs,","taglineSecond":"Façonnés ensemble","cards":[{"id":"about","title":"À propos","logoSrc":"","bodyLines":["Un club d''affaires de mode dirigé par des étudiants de l''Université de Toronto qui tourne autour des valeurs fondamentales d''éducation, de communauté et de réseautage dans l''industrie de la mode.","Le but du RCFG est de fournir aux étudiants de Rotman Commerce l''opportunité de se connecter sur des sujets de mode et de beauté tels que les tendances mondiales, les conseils de style, les carrières en mode et la mode d''affaires.","Nous organisons des événements engageants et créons une communauté dans le monde de la mode.","Rejoignez-nous pour élargir votre réseau et votre passion pour l''industrie."]},{"id":"journey","title":"Mon parcours","logoSrc":"","bodyLines":["Directrice de contenu créatif fév 2024 - Présent","Gestionnaire de contenu créatif fév 2023 - fév 2024"]},{"id":"impact","title":"Impact","logoSrc":"","bodyLines":["450+ participants aux événements étudiants","10 000+ audiences engagées","1 140 abonnés Instagram"]},{"id":"connect","title":"Connectez-vous avec nous","logoSrc":"","bodyLines":[],"isConnectCard":true,"links":[{"label":"Instagram","handle":"@rcfashiongroup","url":"https://www.instagram.com/rcfashiongroup"},{"label":"","handle":"www.rcfashiongroup.com","url":"https://www.rcfashiongroup.com"}]}],"artworkHeading":"Conception de marchandise","artworkBody":"L''équipe de contenu créatif était responsable de la conception artistique pour l''équipe de cette année. Voici quelques idées et itérations après avoir reçu des retours :","artworkImageAlts":["karen - 1 (1).png","karen - 2 (1).png","Untitled50_20240716182107.png"],"artworkImageSrcs":["/img/{person_id}/karen-1-1.avif","/img/{person_id}/karen-2-1.avif","/img/{person_id}/Untitled50_20240716182107.avif"],"creativePostsHeading":"Publications créatives","creativePostsIntro":"Notre équipe pense à des moyens créatifs de promouvoir les événements du club et, lorsqu''il n''y a pas d''événements à venir, exécute de grands projets créatifs tels que des interviews de rue et des reprises Instagram pour divertir notre audience et maintenir des téléchargements cohérents.","events":[{"heading":"Trouvailles de seconde main RCFG","stats":"Ce septembre, pour promouvoir notre événement Thrifting à Toronto, nous avons créé une publication de style scrapbook pour présenter les trouvailles de seconde main de l''équipe exécutive.","statsLines":["759 comptes atteints","85,7% des abonnés","14,3% des non-abonnés"],"imageAlt":"Couverture des trouvailles de seconde main Exec","imageSrc":"/img/{person_id}/ExecThriftFinds.avif"}],"creativeReelsHeading":"Bobines créatives","creativeReelsBody":"Résumés d''événements, Journée dans la vie, et plus bientôt...","showcases":[{"heading":"Directrice de contenu créatif","subtitle":"fév. 2024 - Présent","cards":[{"title":"Leadership","description":"Dirigé un groupe de 5 membres du comité pour augmenter l''engagement et maximiser la participation aux événements."},{"title":"Coordination","description":"Travaillé en étroite collaboration avec les directeurs marketing pour organiser un calendrier de contenu et un calendrier de téléchargement."},{"title":"Exécution","description":"Encouragé la génération d''idées et délégué les tâches aux membres du comité en fonction de leurs forces uniques."},{"title":"Analyse de marché","description":"Resté au courant des tendances Instagram et TikTok et exécuté des publications de contenu créatif en mode."}]}]}]},"specialties":{"pageTitle":"Marketing des médias sociaux | Karen Zhu","title":"Marketing des médias sociaux","sectionTitle":"Rôles de leadership","intro":"À travers mes rôles de leadership étudiant, j''ai créé des graphiques promotionnels et des bobines pour promouvoir les événements et augmenter l''engagement.","roles":[{"title":"Directrice de contenu créatif","organization":"Rotman Commerce Fashion Group","duration":"(2024 - 2025)","imageSrc":"/img/{person_id}/RCFG-headers.avif","imageAlt":"Directrice de contenu créatif - Rotman Commerce Fashion Group","link":"engagements#engagement-0"},{"title":"Directrice marketing et design","organization":"Conseil des finances et du leadership de l''UofT","duration":"(2025 - 2026)","imageSrc":"/img/{person_id}/FLC-headers.avif","imageAlt":"Directrice marketing et design - Conseil des finances et du leadership de l''UofT"}]},"cherish":{"browserTabName":"Services intégrés Cherish - Karen Zhu","hero":{"title":"Services intégrés Cherish","subtitle":"Conception d''un site Web et d''une plateforme de dons pour un événement caritatif","cta_label":"Visiter le site","cta_url":"https://cherish-love-gala-2024.raiselysite.com/"},"organization":{"heading":"Contexte de l''organisation","body":["Cherish Integrated Services (CHIS) est un organisme à but non lucratif et un organisme de bienfaisance enregistré qui sert les personnes ayant une déficience intellectuelle dans la région du Grand Toronto. Ils offrent une variété de programmes pour chaque groupe d''âge pour aider à la formation professionnelle, à l''entreprise de travail et à la vie quotidienne.","CHIS organise un gala annuel Love pour collecter des fonds afin d''élargir davantage ses services et ses installations. Cette année, les recettes serviront à développer leur nouveau centre de formation professionnelle. Cette nouvelle installation aidera davantage de stagiaires développés à travailler dans un vrai environnement de café et à acquérir des compétences employables."]},"role":{"heading":"Mon rôle","title":"Coordinatrice marketing numérique","dates":"Juin 2024 - Août 2024","body":["En tant que seule designer pendant mon mandat, j''ai développé un site Web pour l''événement caritatif Cherish Love Gala 2024 en utilisant la plateforme Raisley. J''ai veillé à inclure des détails importants concernant l''événement et j''ai géré les dons et les ventes de billets entrants.","En plus de l''aspect design, j''ai fortement participé à l''élaboration du package de parrainage et à la communication avec les entreprises locales et les médias concernant l''événement."]},"features":{"centerVideo":"/img/{person_id}/cherish_demo.mp4","centerVideoPoster":"/img/{person_id}/cherish_features.avif","centerVideoAlt":"Démo du site Web Cherish Love Gala","leftItems":[{"title":"Profils des artistes","description":"Création d''une page d''introduction et de dons pour chaque artiste où les supporters peuvent promettre leurs dons."},{"title":"Ventes de billets et dons","description":"Liaison de Powr.io pour les ventes de billets et les déductions de coûts alimentaires dans les reçus fiscaux."}],"rightItems":[{"title":"Détails de l''événement","description":"Informer les invités sur le lieu, la date, l''heure et les inclusions de billets. Décrire la cause à laquelle tous les bénéfices seront consacrés."},{"title":"Commanditaires","description":"Lister tous les supporters, les sponsors d''événements et les sponsors de prix (tombola et vente aux enchères silencieuse) dans le pied de page avec des liens vers leur site Web."}]},"gallery":{"leftImage":{"src":"/img/{person_id}/cherish_performers.avif","alt":"Capture d''écran de la page des artistes du Love Gala"},"middleImages":[{"src":"/img/{person_id}/cherish_donation.avif","alt":"Capture d''écran de la page de promesse de don"},{"src":"/img/{person_id}/cherish_donation2.avif","alt":"Capture d''écran de la page de promesse de don 2"}],"rightImage":{"src":"/img/{person_id}/cherish_about.avif","alt":"Capture d''écran de la page Qu''est-ce que le Cherish Love Gala"}}},"simonSaves":{"browserTabName":"SimonSaves - Karen Zhu","hero":{"title":"SimonSaves","subtitle":"Conception d''application pour la budgétisation des repas","cta_label":"Voir le prototype","cta_url":"https://www.figma.com/proto/xw4hyc3g8zxUA3be71XRB2/Recipe-Book-App-Prototype?type=design&node-id=1-2&t=hYJdCZQe1uISo0eg-1&scaling=scale-down&page-id=0%3A1&starting-point-node-id=180%3A223"},"overview":{"heading":"Aperçu","body":["Notre groupe de 4 personnes s''est classé dans les 3 premiers pour une compétition d''études de cas qui nous a défié de concevoir une solution pour résoudre un problème dans le secteur de la technologie financière. Notre solution a présenté une application qui utilise l''apprentissage automatique pour recommander des recettes et des dépenses alimentaires en fonction des budgets des utilisateurs et de leurs restrictions et préférences alimentaires."]},"keyFeatures":{"title":"Caractéristiques principales","items":["Recherche de recettes et d''épicerie filtrée en fonction des restrictions alimentaires et des recommandations","Résumé de budgétisation alimentaire financière sur la page d''accueil","Cartes d''information fournissant des conseils et des faits sur différents ingrédients","Communauté en ligne pour discuter avec d''autres utilisateurs de l''application et poser des questions","Bannières publicitaires avec défilement sur la page d''accueil pour promouvoir les réductions et les ventes en cours"]},"role":{"heading":"Mon rôle","title":"Designer UX et créatrice de logo","dates":"2023","body":["Grâce à mon expérience avec Figma grâce au cours Google UX Design en ligne, avec un autre membre de l''équipe, nous avons entrepris de développer une application conviviale pour la budgétisation financière et l''éducation alimentaire. Les compétences diverses de notre équipe m''ont permis de diriger le processus de conception et de guider mon coéquipier dans les fonctions de base de Figma.","Ensemble, nous avons travaillé sur des wireframes papier pour trouver des idées, suivi de la création de maquettes pour chaque page de l''application. J''ai ensuite assumé la responsabilité exclusive de l''étape de prototype, en veillant à des interactions transparentes pour tous les boutons.","Grâce à mes antécédents importants en arts visuels, j''ai également entrepris de créer une mascotte et un logo personnalisés pour notre marque. Notre image de marque prétendue était éducative et conviviale, ce qui a conduit à la création de Simon le Persimmon. En tant que groupe, nous avons décidé du nom car nous croyions que les consommateurs s''associeraient immédiatement au fruit unique de notre marque en raison de son nom rimé et de son utilisation peu commune."]},"results":{"heading":"Résultats","body":["Notre groupe s''est qualifié pour le tour de présentation finale où nous avons eu l''occasion de présenter notre idée à un panel de designers UX et produit expérimentés. La présentation finale comprenait 10 minutes de présentation et 5 minutes de questions des panélistes."]},"learnings":{"title":"Apprentissages","items":["Le processus de conception est un cycle continu","Les connaissances de base en technologie sont cruciales","Utilisez les compétences diversifiées des membres de l''équipe avec la délégation des tâches, mais assurez-vous que tous les membres ont voix au chapitre dans chaque aspect du projet pour maximiser le potentiel"]},"gallery":{"mainImage":{"src":"/img/{person_id}/simonSavesMockup.avif","alt":"Capture d''écran de la maquette de l''application SimonSaves"},"mascotImage":{"src":"/img/{person_id}/simonMascot.avif","alt":"Logo de la mascotte Simon le Persimmon"}}}}',
  NOW()
)
ON CONFLICT ("PortfolioId", "Language") DO NOTHING;

