INSERT INTO "PortfolioLocales" ("Id", "PortfolioId", "Language", "ContentJson", "UpdatedAt")
VALUES (
  gen_random_uuid(),
  'EU1O',
  'en',
  '{"common":{"siteName":"Jason Zhu","baseTitle":"Jason Zhu","nav":[{"label":"Achievements","path":"engagements"},{"label":"About Me","path":"about"}],"languageLabel":"Language","languages":{"en":"English","fr":"Français","zh":"中文"},"toggleNavMenu":"Toggle navigation menu","footer":"© 2026 by Jason Zhu | Senior Software Engineering Leader","showcases":[{"title":"Platform Modernization Initiative","subtitle":"Leading a large-scale cloud migration and microservices transformation","cta_label":"View Details","cta_url":"https://example.com","carouselImages":[{"imageSrc":"/img/{person_id}/platform_arch_1.png","imageAlt":"Legacy system architecture"},{"imageSrc":"/img/{person_id}/platform_arch_2.png","imageAlt":"Modern cloud-based architecture"},{"imageSrc":"/img/{person_id}/platform_metrics.png","imageAlt":"Performance improvements dashboard"}],"features":[{"title":"Architecture Design","description":"Designed and implemented a modern, scalable cloud-native architecture using microservices principles, containerization with Docker/Kubernetes, and event-driven patterns to replace the monolithic legacy system."},{"title":"Team Leadership","description":"Led cross-functional teams of developers, architects, and DevOps engineers through the complex migration process, ensuring clear communication and alignment on technical decisions and timelines."},{"title":"Risk Management","description":"Implemented comprehensive risk mitigation strategies including parallel running, canary deployments, and rollback procedures to ensure zero downtime and data integrity during the transition."},{"title":"Performance Optimization","description":"Achieved 60% reduction in latency, 40% cost savings, and 99.99% uptime through optimized caching strategies, load balancing, and auto-scaling capabilities in the new cloud infrastructure."}],"stories":[{"title":"The Challenge","subtitle":"Moving from Monolith to Microservices","description":"The organization was operating on a 15-year-old monolithic application that had become increasingly difficult to scale and maintain. The system experienced frequent outages, had long deployment cycles, and couldn''t support the company''s growth ambitions.","images":[{"imageSrc":"/img/{person_id}/legacy_system.png","imageAlt":"Legacy monolithic system architecture diagram"}],"footer":"This transformation required careful planning, stakeholder management, and a phased approach to minimize business impact while maximizing technical improvements."},{"title":"The Solution","subtitle":"Building the Future Platform","description":"We implemented a comprehensive modernization strategy that included breaking down the monolith into independently deployable microservices, adopting containerization for consistency, and leveraging AWS services for scalability and reliability.","images":[{"imageSrc":"/img/{person_id}/microservices_arch.png","imageAlt":"Microservices architecture with event streaming"},{"imageSrc":"/img/{person_id}/kubernetes_deployment.png","imageAlt":"Kubernetes cluster deployment diagram"}],"footer":"The new platform reduced operational overhead, improved developer productivity, and enabled the organization to deploy updates multiple times per day with confidence."}]}]},"theme":{"fontFamily":"Comic Neue"},"home":{"hero":{"title":"Jason Zhu","subtitle":"Technology Management | Software Engineering | Team & Platform Builder","intro":"Sr. technology leader with 25+ years of experience leading software architecture, development, and transformation initiatives in Health, Insurance, and Group Benefits. Expert in AI-powered automation, scalable enterprise platforms, cloud and agile delivery. Known for driving innovation, operational efficiency, and measurable business outcomes."},"features":{"title":"Explore My Specialties","items":[{"icon":"/img/{person_id}/home_architecture.png","title":"Architecture & Strategy","path":"specialties"},{"icon":"/img/{person_id}/home_agile.png","title":"Agile Methodologies","path":"specialties"},{"icon":"/img/{person_id}/home_ai_dev.png","title":"AI-assisted Development","path":"specialties"},{"icon":"/img/{person_id}/home_architecture.png","title":"Innovation & Transformation","path":"specialties"},{"icon":"/img/{person_id}/home_architecture.png","title":"Health Insurance","path":"specialties"}]},"topEngagements":[]},"about":{"pageTitle":"About Me | Jason Zhu","title":"Jason Zhu","subtitle":"About Me","avatarAlt":"Personal character illustration","avatarSrc":"/img/{person_id}/Personal-Character-Jason.png","hobbiesImageSrc":"/img/{person_id}/aboutMe_hobbies.png","aboutParagraphs":["I’m a technology leader with 25+ years of experience building and scaling enterprise software platforms across healthcare, insurance, and group benefits. My work sits at the intersection of technology strategy, software engineering, and people leadership. I’ve led large-scale modernization initiatives—cloud migration, legacy re-architecture, and API-driven platforms—while delivering highly reliable systems that process millions of transactions annually. Whether defining a long-term technology roadmap or guiding teams through complex delivery challenges, I focus on creating solutions that are scalable, resilient, and closely aligned with business outcomes.","I’m deeply passionate about building strong engineering teams and healthy delivery cultures. Over the years, I’ve grown and led cross-functional teams of 50+ engineers, improving delivery speed, quality, and engagement through Agile practices, DevOps, and Team Topologies. I remain hands-on by choice—still coding, prototyping, and experimenting—especially in areas like AI-assisted development and automation. I believe that great technology leadership is about multiplying impact: empowering people, simplifying complexity, and turning innovation into measurable value."],"funFactsTitle":"Some Fun Facts","funFacts":["Sports Enthusiast: Whether it''s the finesse of badminton, the precision of snooker, or the thrill of soccer (especially a last-minute goal!), I’m always game for competition and strategy.","Travel Buff: I make the most of my vacations by exploring new cultures, landscapes, and cuisines. Each trip adds a new layer to how I see the world — and sometimes inspires my next tech experiment."]},"engagements":{"items":[{"pageTitle":"Achievements | Jason Zhu","logoSrc":"/img/{person_id}/engagements_adjudicare.png","logoAlt":"TELUS AdjudiCare","title":"TELUS AdjudiCare","taglineFirst":"Claims processing workflow,","taglineSecond":"Automated payment process","cards":[{"id":"about","title":"About","logoSrc":"","bodyLines":["A health insurance claims adjudication and payment solution hosted in aws with the world class level of resilience, scalability, and security.","Robust configuration rules enable TPAs and insurers to customize claims processing and payment workflows efficiently.","API driven architecture allows seamless integration with third-party systems for eligibility and claim data exchange."]},{"id":"journey","title":"Claim Journey","logoSrc":"","bodyLines":["<Icon icon=''arrowRightToBracket'' /> Claim received electronically or batch imported by users","<Icon icon=''personCircleQuestion'' /> Claim pended for manual review","<Icon icon=''gears'' /> Claim adjudicated based on plan design and configuration rules","<Icon icon=''moneyCheckDollar'' /> Payment processed automatically via EFT or cheque generation"]},{"id":"impact","title":"Impact","logoSrc":"","bodyLines":["<Icon icon=''peopleLine'' /> Hundreds of thousands certificates onboarded with ease and equipped with mobile access","<Icon icon=''hospitalUser'' /> Registered healthcare providers across Canada enabled for electronic claims submission","<Icon icon=''handHoldingDollar'' /> Significant operational and benefit cost savings to insurers, TPAs and plan sponsors through automation and fraud detection."]},{"id":"connect","title":"Apps","logoSrc":"","bodyLines":[],"isConnectCard":true,"links":[{"label":"TPA Website","handle":"www.adjudicare.net","url":"https://www.adjudicare.net"},{"label":"","handle":"Member Web Portal","url":"https://www.onlineclaimsaccess.net"},{"label":"","handle":"Member iOS App","url":"https://apps.apple.com/ca/app/my-health-benefits/id671060840"},{"label":"","handle":"Member Android App","url":"https://play.google.com/store/apps/details?id=ca.symbilityhealth.mobileclaims&pli=1"}]}],"artworkHeading":"","artworkBody":"","artworkImageAlts":[],"artworkImageSrcs":[],"creativePostsHeading":"","creativePostsIntro":"","events":[],"creativeReelsHeading":"","creativeReelsBody":"","showcases":[{"heading":"Director of Software Engineering","subtitle":"May 2018 - November 2025 at TELUS","cards":[{"title":"Leadership","description":"Built and scaled a 50+ member cross-functional engineering team, achieving 60% improvement in delivery velocity through agile transformation, DevOps practices, and hands-on coaching."},{"title":"Growth","description":"Created a high-performance culture fostering collaboration, technical excellence, and career development across globally distributed teams. Drove 4x revenue growth through strategic client onboarding and successful service expansion post-acquisition."},{"title":"Execution","description":"Led enterprise-scale modernization initiatives including on-premises to AWS cloud migration, transforming to microservices architecture and complete UI rebuild with Angular—all delivered on time and within scope."},{"title":"Compliance","description":"Established robust security and privacy practices, ensuring SOC 2 Type II compliance. Partnered with KPMG for annual audits, maintaining world-class standards for healthcare and insurance data protection."}]},{"heading":"VP of Software Development","subtitle":"June 2004 - May 2018 at Symbility Health (Acquired by TELUS)","cards":[{"title":"Insurance Expertise","description":"Progressed from developer to senior leader, mastering full-stack software development while building deep domain expertise in Group Insurance Administration and Health Claims Adjudication."},{"title":"Innovation","description":"Spearheaded development of Specialty Pharmacy Management (Biometrx) and Patient Support platforms, expanding footprint into pharmaceutical and specialty care sectors."},{"title":"Process Excellence","description":"Introduced Agile Scrum framework and drove continuous process improvements, including CI/CD pipelines and test automation, significantly enhancing team productivity and release quality."},{"title":"Compliance","description":"Supported Symbility''s ISO 27001 certification by implementing and validating required security controls and information security management practices."}]}]}]},"specialties":{"pageTitle":"Specialties | Jason Zhu","title":"Health Insurance Engineering","sectionTitle":"Emerging Technologies transforming Insurance industry","intro":"Plan members and healthcare providers expect seamless digital experiences when accessing their insurance information, submitting claims, and receiving payments. To meet these expectations, insurers and third-party administrators (TPAs) must leverage emerging technologies to modernize their legacy systems and processes. Key technologies such as AI-assisted development, cloud computing, microservices architecture, and API-driven platforms are revolutionizing how insurance solutions are designed, built, and delivered. By embracing these innovations, insurers can enhance operational efficiency, improve customer satisfaction, and drive business growth in a competitive market.","roles":[{"title":"Strategic Technology Leader with Health Insurance Domain Expertise","organization":"Driving Scalable Health Benefit Management and Claim Adjudication Platforms","duration":"(2012 - 2025)","imageSrc":"/img/{person_id}/specialty_claims_solution.png","imageAlt":"Strategic Technology Leader - Health Benefit Management and Adjudication Systems","link":"engagements#engagement-0"},{"title":"From Programmer to Principal Engineer","organization":"Full-stack engineering experience in architecture, design, coding, testing, maintenance and DevOps","duration":"(1998 - 2025)","imageSrc":"/img/{person_id}/specialty_technology_evolution.png","imageAlt":"Director of Marketing & Design - UofT Finance & Leadership Council"}]}}',
  NOW()
)
ON CONFLICT ("PortfolioId", "Language") DO NOTHING;

