INSERT INTO "PortfolioLocales" ("Id", "PortfolioId", "Language", "ContentJson", "UpdatedAt")
VALUES (
  gen_random_uuid(),
  'EU1O',
  'fr',
  '{"common":{"siteName":"Jason Zhu","baseTitle":"Jason Zhu","nav":[{"label":"Réalisations","path":"engagements"},{"label":"À propos de moi","path":"about"}],"languageLabel":"Langue","languages":{"en":"English","fr":"Français","zh":"中文"},"toggleNavMenu":"Basculer le menu de navigation","footer":"© 2026 par Jason Zhu | Leader en ingénierie logicielle senior","showcases":[{"title":"Initiative de Modernisation de la Plateforme","subtitle":"Direction d''une migration cloud à grande échelle et d''une transformation en microservices","cta_label":"Voir les Détails","cta_url":"https://example.com","carouselImages":[{"imageSrc":"/img/{person_id}/platform_arch_1.png","imageAlt":"Architecture système héritée"},{"imageSrc":"/img/{person_id}/platform_arch_2.png","imageAlt":"Architecture moderne basée sur le cloud"},{"imageSrc":"/img/{person_id}/platform_metrics.png","imageAlt":"Tableau de bord des améliorations de performance"}],"features":[{"title":"Conception d''Architecture","description":"J''ai conçu et mis en œuvre une architecture cloud-native moderne et évolutive utilisant les principes des microservices, la containerisation avec Docker/Kubernetes, et les modèles basés sur les événements pour remplacer le système monolithique hérité."},{"title":"Direction d''Équipe","description":"J''ai dirigé des équipes multidisciplinaires de développeurs, d''architectes et d''ingénieurs DevOps tout au long du processus de migration complexe, en assurant une communication claire et un alignement sur les décisions techniques et les calendriers."},{"title":"Gestion des Risques","description":"J''ai mis en place des stratégies complètes d''atténuation des risques incluant l''exécution parallèle, les déploiements canary, et les procédures de restauration pour assurer un temps d''arrêt zéro et l''intégrité des données lors de la transition."},{"title":"Optimisation des Performances","description":"J''ai réalisé une réduction de 60% de la latence, des économies de coûts de 40%, et une disponibilité de 99,99% grâce à des stratégies de mise en cache optimisées, l''équilibrage de charge, et les capacités de mise à l''échelle automatique dans la nouvelle infrastructure cloud."}],"stories":[{"title":"Le Défi","subtitle":"Passer du Monolithe aux Microservices","description":"L''organisation fonctionnait sur une application monolithique vieille de 15 ans qui était devenue de plus en plus difficile à mettre à l''échelle et à maintenir. Le système subissait des pannes fréquentes, avait des cycles de déploiement longs, et ne pouvait pas soutenir les ambitions de croissance de l''entreprise.","images":[{"imageSrc":"/img/{person_id}/legacy_system.png","imageAlt":"Diagramme d''architecture du système monolithique hérité"}],"footer":"Cette transformation a nécessité une planification minutieuse, la gestion des parties prenantes, et une approche progressive pour minimiser l''impact commercial tout en maximisant les améliorations techniques."},{"title":"La Solution","subtitle":"Construire la Plateforme de l''Avenir","description":"Nous avons mis en œuvre une stratégie de modernisation complète qui comprenait la décomposition du monolithe en microservices indépendamment déployables, l''adoption de la containerisation pour la cohérence, et l''exploitation des services AWS pour la scalabilité et la fiabilité.","images":[{"imageSrc":"/img/{person_id}/microservices_arch.png","imageAlt":"Architecture des microservices avec flux d''événements"},{"imageSrc":"/img/{person_id}/kubernetes_deployment.png","imageAlt":"Diagramme de déploiement du cluster Kubernetes"}],"footer":"La nouvelle plateforme a réduit les frais opérationnels, amélioré la productivité des développeurs, et permis à l''organisation de déployer des mises à jour plusieurs fois par jour en toute confiance."}]}]},"theme":{"fontFamily":"Comic Neue"},"home":{"hero":{"title":"Jason Zhu","subtitle":"Gestion technologique | Ingénierie logicielle | Constructeur d''équipes et de plateformes","intro":"Leader technologique senior avec plus de 25 ans d''expérience dans la direction d''initiatives d''architecture logicielle, de développement et de transformation dans les secteurs de la santé, de l''assurance et des avantages sociaux collectifs. Expert en automatisation alimentée par l''IA, plateformes d''entreprise évolutives, cloud et livraison agile. Reconnu pour favoriser l''innovation, l''efficacité opérationnelle et des résultats commerciaux mesurables."},"features":{"title":"Explorez mes spécialités","items":[{"icon":"/img/{person_id}/home_architecture.png","title":"Architecture et stratégie","path":"specialties"},{"icon":"/img/{person_id}/home_agile.png","title":"Méthodologies agiles","path":"specialties"},{"icon":"/img/{person_id}/home_ai_dev.png","title":"Développement assisté par l''IA","path":"specialties"},{"icon":"/img/{person_id}/home_architecture.png","title":"Innovation et transformation","path":"specialties"},{"icon":"/img/{person_id}/home_architecture.png","title":"Assurance santé","path":"specialties"}]},"topEngagements":[]},"about":{"pageTitle":"À propos de moi | Jason Zhu","title":"Jason Zhu","subtitle":"À propos de moi","avatarAlt":"Illustration de personnage personnel","avatarSrc":"/img/{person_id}/Personal-Character-Jason.png","hobbiesImageSrc":"/img/{person_id}/aboutMe_hobbies.png","aboutParagraphs":["Je suis un leader technologique avec plus de 25 ans d''expérience dans la construction et la mise à l''échelle de plateformes logicielles d''entreprise dans les secteurs de la santé, de l''assurance et des avantages sociaux collectifs. Mon travail se situe à l''intersection de la stratégie technologique, de l''ingénierie logicielle et du leadership humain. J''ai dirigé des initiatives de modernisation à grande échelle — migration vers le cloud, refonte d''architecture héritée et plateformes basées sur des API — tout en livrant des systèmes hautement fiables qui traitent des millions de transactions annuellement. Que ce soit pour définir une feuille de route technologique à long terme ou guider des équipes à travers des défis de livraison complexes, je me concentre sur la création de solutions évolutives, résilientes et étroitement alignées avec les objectifs commerciaux.","Je suis profondément passionné par la construction d''équipes d''ingénierie solides et de cultures de livraison saines. Au fil des ans, j''ai développé et dirigé des équipes interfonctionnelles de plus de 50 ingénieurs, améliorant la vitesse de livraison, la qualité et l''engagement grâce aux pratiques agiles, DevOps et Team Topologies. Je reste impliqué sur le terrain par choix — continuant à coder, prototyper et expérimenter — en particulier dans des domaines comme le développement assisté par l''IA et l''automatisation. Je crois qu''un excellent leadership technologique consiste à multiplier l''impact : autonomiser les gens, simplifier la complexité et transformer l''innovation en valeur mesurable."],"funFactsTitle":"Quelques faits amusants","funFacts":["Passionné de sport : Que ce soit la finesse du badminton, la précision du snooker ou le frisson du soccer (surtout un but à la dernière minute !), je suis toujours prêt pour la compétition et la stratégie.","Amateur de voyages : Je profite au maximum de mes vacances en explorant de nouvelles cultures, paysages et cuisines. Chaque voyage ajoute une nouvelle dimension à ma vision du monde — et inspire parfois ma prochaine expérience technologique."]},"engagements":{"items":[{"pageTitle":"Réalisations | Jason Zhu","logoSrc":"/img/{person_id}/engagements_adjudicare.png","logoAlt":"TELUS AdjudiCare","title":"TELUS AdjudiCare","taglineFirst":"Flux de traitement des demandes de remboursement,","taglineSecond":"Processus de paiement automatisé","cards":[{"id":"about","title":"À propos","logoSrc":"","bodyLines":["Une solution d''adjudication et de paiement de demandes de remboursement d''assurance santé hébergée sur AWS avec un niveau mondial de résilience, d''évolutivité et de sécurité.","Des règles de configuration robustes permettent aux TPA et aux assureurs de personnaliser efficacement les flux de traitement des demandes de remboursement et de paiement.","L''architecture basée sur les API permet une intégration transparente avec des systèmes tiers pour l''échange de données d''admissibilité et de demandes de remboursement."]},{"id":"journey","title":"Parcours de la demande","logoSrc":"","bodyLines":["<Icon icon=''arrowRightToBracket'' /> Demande reçue électroniquement ou importée par lot par les utilisateurs","<Icon icon=''personCircleQuestion'' /> Demande en attente d''examen manuel","<Icon icon=''gears'' /> Demande adjugée selon la conception du régime et les règles de configuration","<Icon icon=''moneyCheckDollar'' /> Paiement traité automatiquement via TED ou génération de chèque"]},{"id":"impact","title":"Impact","logoSrc":"","bodyLines":["<Icon icon=''peopleLine'' /> Des centaines de milliers de certificats intégrés facilement et équipés d''un accès mobile","<Icon icon=''hospitalUser'' /> Fournisseurs de soins de santé enregistrés à travers le Canada habilités pour la soumission électronique de demandes","<Icon icon=''handHoldingDollar'' /> Économies opérationnelles et de coûts d''avantages significatives pour les assureurs, les TPA et les promoteurs de régimes grâce à l''automatisation et à la détection de fraude."]},{"id":"connect","title":"Applications","logoSrc":"","bodyLines":[],"isConnectCard":true,"links":[{"label":"Site Web TPA","handle":"www.adjudicare.net","url":"https://www.adjudicare.net"},{"label":"","handle":"Portail Web des membres","url":"https://www.onlineclaimsaccess.net"},{"label":"","handle":"Application iOS des membres","url":"https://apps.apple.com/ca/app/my-health-benefits/id671060840"},{"label":"","handle":"Application Android des membres","url":"https://play.google.com/store/apps/details?id=ca.symbilityhealth.mobileclaims&pli=1"}]}],"artworkHeading":"","artworkBody":"","artworkImageAlts":[],"artworkImageSrcs":[],"creativePostsHeading":"","creativePostsIntro":"","events":[],"creativeReelsHeading":"","creativeReelsBody":"","showcases":[{"heading":"Directeur de l''ingénierie logicielle","subtitle":"Mai 2018 - Novembre 2025 chez TELUS","cards":[{"title":"Leadership","description":"Construit et mis à l''échelle une équipe d''ingénierie interfonctionnelle de plus de 50 membres, atteignant une amélioration de 60% de la vélocité de livraison grâce à la transformation agile, aux pratiques DevOps et au coaching pratique."},{"title":"Croissance","description":"Créé une culture de haute performance favorisant la collaboration, l''excellence technique et le développement de carrière au sein d''équipes distribuées mondialement. Stimulé une croissance des revenus de 4x grâce à l''intégration stratégique de clients et à l''expansion réussie des services après l''acquisition."},{"title":"Exécution","description":"Dirigé des initiatives de modernisation à l''échelle de l''entreprise, y compris la migration sur site vers le cloud AWS, la transformation vers une architecture de microservices et la reconstruction complète de l''interface utilisateur avec Angular — tout livré dans les délais et dans les limites du périmètre."},{"title":"Conformité","description":"Établi des pratiques robustes de sécurité et de confidentialité, assurant la conformité SOC 2 Type II. Partenariat avec KPMG pour les audits annuels, maintenant des normes de classe mondiale pour la protection des données de santé et d''assurance."}]},{"heading":"VP du développement logiciel","subtitle":"Juin 2004 - Mai 2018 chez Symbility Health (Acquis par TELUS)","cards":[{"title":"Expertise en assurance","description":"Progression de carrière de développeur à leader senior, maîtrisant le développement logiciel full-stack tout en développant une expertise approfondie du domaine dans l''administration des assurances collectives et l''adjudication des demandes de remboursement santé."},{"title":"Innovation","description":"Dirigé le développement de plateformes de gestion de pharmacie spécialisée (Biometrx) et de soutien aux patients, élargissant notre présence dans les secteurs pharmaceutique et des soins spécialisés."},{"title":"Excellence des processus","description":"Introduit le cadre Agile Scrum et favorisé l''amélioration continue des processus, y compris les pipelines CI/CD et l''automatisation des tests, améliorant considérablement la productivité de l''équipe et la qualité des versions."},{"title":"Conformité","description":"Soutenu la certification ISO 27001 de Symbility en mettant en œuvre et en validant les contrôles de sécurité requis et les pratiques de gestion de la sécurité de l''information."}]}]}]},"specialties":{"pageTitle":"Spécialités | Jason Zhu","title":"Ingénierie de l''assurance santé","sectionTitle":"Technologies émergentes transformant l''industrie de l''assurance","intro":"Les membres du régime et les fournisseurs de soins de santé s''attendent à des expériences numériques transparentes lors de l''accès à leurs informations d''assurance, de la soumission de demandes de remboursement et de la réception de paiements. Pour répondre à ces attentes, les assureurs et les administrateurs tiers (TPA) doivent tirer parti des technologies émergentes pour moderniser leurs systèmes et processus hérités. Les technologies clés telles que le développement assisté par l''IA, le cloud computing, l''architecture de microservices et les plateformes basées sur les API révolutionnent la façon dont les solutions d''assurance sont conçues, construites et livrées. En adoptant ces innovations, les assureurs peuvent améliorer l''efficacité opérationnelle, améliorer la satisfaction client et stimuler la croissance commerciale dans un marché concurrentiel.","roles":[{"title":"Leader technologique stratégique avec expertise du domaine de l''assurance santé","organization":"Conduire des plateformes évolutives de gestion des avantages santé et d''adjudication des demandes","duration":"(2012 - 2025)","imageSrc":"/img/{person_id}/specialty_claims_solution.png","imageAlt":"Leader technologique stratégique - Gestion des avantages santé et systèmes d''adjudication","link":"engagements#engagement-0"},{"title":"De programmeur à ingénieur principal","organization":"Expérience d''ingénierie full-stack en architecture, conception, codage, tests, maintenance et DevOps","duration":"(1998 - 2025)","imageSrc":"/img/{person_id}/specialty_technology_evolution.png","imageAlt":"Directeur marketing et design - Conseil des finances et du leadership de l''UofT"}]},"cherish":{"browserTabName":"Services intégrés Cherish - Jason Zhu","hero":{"title":"Services intégrés Cherish","subtitle":"Conception d''un site Web et d''une plateforme de dons pour un événement caritatif","cta_label":"Visiter le site","cta_url":"https://cherish-love-gala-2024.raiselysite.com/"},"organization":{"heading":"Contexte de l''organisation","body":["Cherish Integrated Services (CHIS) est un organisme à but non lucratif et un organisme de bienfaisance enregistré qui sert les personnes ayant une déficience intellectuelle dans la région du Grand Toronto. Ils offrent une variété de programmes pour chaque groupe d''âge pour aider à la formation professionnelle, à l''entreprise de travail et à la vie quotidienne.","CHIS organise un gala annuel Love pour collecter des fonds afin d''élargir davantage ses services et ses installations. Cette année, les recettes serviront à développer leur nouveau centre de formation professionnelle. Cette nouvelle installation aidera davantage de stagiaires développés à travailler dans un vrai environnement de café et à acquérir des compétences employables."]},"role":{"heading":"Mon rôle","title":"Coordinatrice marketing numérique","dates":"Juin 2024 - Août 2024","body":["En tant que seule designer pendant mon mandat, j''ai développé un site Web pour l''événement caritatif Cherish Love Gala 2024 en utilisant la plateforme Raisley. J''ai veillé à inclure des détails importants concernant l''événement et j''ai géré les dons et les ventes de billets entrants.","En plus de l''aspect design, j''ai fortement participé à l''élaboration du package de parrainage et à la communication avec les entreprises locales et les médias concernant l''événement."]},"features":{"centerVideo":"/img/{person_id}/cherish_demo.mp4","centerVideoPoster":"/img/{person_id}/cherish_features.avif","centerVideoAlt":"Démo du site Web Cherish Love Gala","leftItems":[{"title":"Profils des artistes","description":"Création d''une page d''introduction et de dons pour chaque artiste où les supporters peuvent promettre leurs dons."},{"title":"Ventes de billets et dons","description":"Liaison de Powr.io pour les ventes de billets et les déductions de coûts alimentaires dans les reçus fiscaux."}],"rightItems":[{"title":"Détails de l''événement","description":"Informer les invités sur le lieu, la date, l''heure et les inclusions de billets. Décrire la cause à laquelle tous les bénéfices seront consacrés."},{"title":"Commanditaires","description":"Lister tous les supporters, les sponsors d''événements et les sponsors de prix (tombola et vente aux enchères silencieuse) dans le pied de page avec des liens vers leur site Web."}]},"gallery":{"leftImage":{"src":"/img/{person_id}/cherish_performers.avif","alt":"Capture d''écran de la page des artistes du Love Gala"},"middleImages":[{"src":"/img/{person_id}/cherish_donation.avif","alt":"Capture d''écran de la page de promesse de don"},{"src":"/img/{person_id}/cherish_donation2.avif","alt":"Capture d''écran de la page de promesse de don 2"}],"rightImage":{"src":"/img/{person_id}/cherish_about.avif","alt":"Capture d''écran de la page Qu''est-ce que le Cherish Love Gala"}}},"simonSaves":{"browserTabName":"SimonSaves - Jason Zhu","hero":{"title":"SimonSaves","subtitle":"Finaliste du Design Dash du Rotman Commerce Innovation Group x Rotman Commerce Fintech Association","cta_label":"Voir le prototype","cta_url":"https://www.figma.com/proto/xw4hyc3g8zxUA3be71XRB2/Recipe-Book-App-Prototype?type=design&node-id=1-2&t=hYJdCZQe1uISo0eg-1&scaling=scale-down&page-id=0%3A1&starting-point-node-id=180%3A223"},"overview":{"heading":"Aperçu","body":["Notre groupe de 4 personnes s''est classé dans les 3 premiers pour une compétition d''études de cas qui nous a défié de concevoir une solution pour résoudre un problème dans le secteur de la technologie financière. Notre solution a présenté une application qui utilise l''apprentissage automatique pour recommander des recettes et des dépenses alimentaires en fonction des budgets des utilisateurs et de leurs restrictions et préférences alimentaires."]},"keyFeatures":{"title":"Caractéristiques principales","items":["Recherche de recettes et d''épicerie filtrée en fonction des restrictions alimentaires et des recommandations","Résumé de budgétisation alimentaire financière sur la page d''accueil","Cartes d''information fournissant des conseils et des faits sur différents ingrédients","Communauté en ligne pour discuter avec d''autres utilisateurs de l''application et poser des questions","Bannières publicitaires avec défilement sur la page d''accueil pour promouvoir les réductions et les ventes en cours"]},"role":{"heading":"Mon rôle","title":"Designer UX et créateur de logo","dates":"2023","body":["Grâce à mon expérience avec Figma grâce au cours Google UX Design en ligne, avec un autre membre de l''équipe, nous avons entrepris de développer une application conviviale pour la budgétisation financière et l''éducation alimentaire. Les compétences diverses de notre équipe m''ont permis de diriger le processus de conception et de guider mon coéquipier dans les fonctions de base de Figma.","Ensemble, nous avons travaillé sur des wireframes papier pour trouver des idées, suivi de la création de maquettes pour chaque page de l''application. J''ai ensuite assumé la responsabilité exclusive de l''étape de prototype, en veillant à des interactions transparentes pour tous les boutons.","Grâce à mes antécédents importants en arts visuels, j''ai également entrepris de créer une mascotte et un logo personnalisés pour notre marque. Notre image de marque prétendue était éducative et conviviale, ce qui a conduit à la création de Simon le Persimmon. En tant que groupe, nous avons décidé du nom car nous croyions que les consommateurs s''associeraient immédiatement au fruit unique de notre marque en raison de son nom rimé et de son utilisation peu commune."]},"results":{"heading":"Résultats","body":["Notre groupe s''est qualifié pour le tour de présentation finale où nous avons eu l''occasion de présenter notre idée à un panel de designers UX et produit expérimentés. La présentation finale comprenait 10 minutes de présentation et 5 minutes de questions des panélistes."]},"learnings":{"title":"Apprentissages","items":["Le processus de conception est un cycle continu","Les connaissances de base en technologie sont cruciales","Utilisez les compétences diversifiées des membres de l''équipe avec la délégation des tâches, mais assurez-vous que tous les membres ont voix au chapitre dans chaque aspect du projet pour maximiser le potentiel"]},"gallery":{"mainImage":{"src":"/img/{person_id}/SimonSaves_Mockup.avif","alt":"Capture d''écran de la maquette de l''application SimonSaves"},"mascotImage":{"src":"/img/{person_id}/SimonSaves_Logo.avif","alt":"Logo de la mascotte Simon le Persimmon"}}}}',
  NOW()
)
ON CONFLICT ("PortfolioId", "Language") DO NOTHING;

