VALUES (
  gen_random_uuid(),
  'EU1O',
  'zh',
  '{"common":{"siteName":"Jason Zhu","baseTitle":"Jason Zhu","nav":[{"label":"成就","path":"engagements"},{"label":"关于我","path":"about"}],"languageLabel":"语言","languages":{"en":"English","fr":"Français","zh":"中文"},"toggleNavMenu":"切换导航菜单","footer":"© 2026 Jason Zhu | 高级软件工程领导者","showcases":[{"title":"平台现代化计划","subtitle":"领导大规模云迁移和微服务转型","cta_label":"查看详情","cta_url":"https://example.com","carouselImages":[{"imageSrc":"/img/{person_id}/platform_arch_1.png","imageAlt":"传统系统架构"},{"imageSrc":"/img/{person_id}/platform_arch_2.png","imageAlt":"现代云架构"},{"imageSrc":"/img/{person_id}/platform_metrics.png","imageAlt":"性能改进仪表板"}],"features":[{"title":"架构设计","description":"设计并实施了现代的、可扩展的云原生架构，采用微服务原则、使用Docker/Kubernetes的容器化，以及事件驱动模式来替代单体的传统系统。"},{"title":"团队领导","description":"领导开发人员、架构师和DevOps工程师组成的跨职能团队完成复杂的迁移过程，确保在技术决策和时间表上的清晰沟通和一致性。"},{"title":"风险管理","description":"实施了全面的风险缓解策略，包括平行运行、金丝雀部署和回滚程序，以确保迁移过程中零停机和数据完整性。"},{"title":"性能优化","description":"通过优化缓存策略、负载均衡和新云基础设施中的自动扩展功能，实现了60%的延迟降低、40%的成本节省和99.99%的正常运行时间。"}],"stories":[{"title":"挑战","subtitle":"从单体到微服务的转变","description":"该组织运营一个有15年历史的单体应用程序，它变得越来越难以扩展和维护。系统经常出现故障，部署周期长，无法支持公司的增长雄心。","images":[{"imageSrc":"/img/{person_id}/legacy_system.png","imageAlt":"传统单体系统架构图"}],"footer":"这次转型需要仔细的计划、利益相关者管理和分阶段的方法，以最小化业务影响，同时最大化技术改进。"},{"title":"解决方案","subtitle":"构建未来的平台","description":"我们实施了一项全面的现代化战略，包括将单体分解为独立可部署的微服务，采用容器化实现一致性，并利用AWS服务实现可扩展性和可靠性。","images":[{"imageSrc":"/img/{person_id}/microservices_arch.png","imageAlt":"具有事件流的微服务架构"},{"imageSrc":"/img/{person_id}/kubernetes_deployment.png","imageAlt":"Kubernetes集群部署图"}],"footer":"新平台降低了运营开销，提高了开发人员生产力，使组织能够每天多次自信地部署更新。"}]}]},"theme":{"fontFamily":"Comic Neue"},"home":{"hero":{"title":"Jason Zhu","subtitle":"技术管理 | 软件工程 | 团队与平台构建者","intro":"拥有25年以上经验的资深技术领导者，专业从事健康、保险和集体福利领域的软件架构、开发和转型倡议。擅长AI驱动的自动化、可扩展企业平台、云计算和敏捷交付。以推动创新、运营效率和可衡量的业务成果而闻名。"},"features":{"title":"探索我的专业领域","items":[{"icon":"/img/{person_id}/home_architecture.png","title":"架构与战略","path":"specialties"},{"icon":"/img/{person_id}/home_agile.png","title":"敏捷方法论","path":"specialties"},{"icon":"/img/{person_id}/home_ai_dev.png","title":"AI辅助开发","path":"specialties"},{"icon":"/img/{person_id}/home_architecture.png","title":"创新与转型","path":"specialties"},{"icon":"/img/{person_id}/home_architecture.png","title":"健康保险","path":"specialties"}]},"topEngagements":[]},"about":{"pageTitle":"关于我 | Jason Zhu","title":"Jason Zhu","subtitle":"关于我","avatarAlt":"个人角色插图","avatarSrc":"/img/{person_id}/Personal-Character-Jason.png","hobbiesImageSrc":"/img/{person_id}/aboutMe_hobbies.png","aboutParagraphs":["我是一位技术领导者，拥有25年以上经验，在医疗保健、保险和集体福利领域建立和扩展企业软件平台。我的工作处于技术战略、软件工程和人员领导的交界点。我领导过大规模现代化倡议——云迁移、遗留系统重构和API驱动平台——同时提供每年处理数百万笔交易的高度可靠的系统。无论是定义长期技术路线图还是指导团队应对复杂交付挑战，我都专注于创建可扩展、有弹性且与业务成果紧密结合的解决方案。","我对建立强大的工程团队和健康的交付文化充满热情。多年来，我建立并领导了拥有50多名工程师的跨职能团队，通过敏捷实践、DevOps和团队拓扑学改进交付速度、质量和参与度。我选择保持动手——继续编码、原型设计和实验——特别是在AI辅助开发和自动化等领域。我相信伟大的技术领导力是关于倍增影响：赋权员工、简化复杂性、将创新转化为可衡量的价值。"],"funFactsTitle":"一些有趣的事实","funFacts":["运动爱好者：无论是羽毛球的精妙、斯诺克的精准，还是足球的刺激（尤其是最后一刻的进球！），我总是乐于竞争和策略。","旅游爱好者：我通过探索新的文化、风景和美食来充分利用我的假期。每次旅行都为我对世界的看法增添了新的层面——有时还会启发我的下一个技术实验。"]},"engagements":{"items":[{"pageTitle":"成就 | Jason Zhu","logoSrc":"/img/{person_id}/engagements_adjudicare.png","logoAlt":"TELUS AdjudiCare","title":"TELUS AdjudiCare","taglineFirst":"索赔处理工作流，","taglineSecond":"自动化支付流程","cards":[{"id":"about","title":"关于","logoSrc":"","bodyLines":["一个在AWS上托管的健康保险索赔裁定和支付解决方案，具有世界级的弹性、可扩展性和安全性。","强大的配置规则使第三方管理员和保险公司能够有效地定制索赔处理和支付工作流。","基于API的架构允许与第三方系统无缝集成，用于资格和索赔数据交换。"]},{"id":"journey","title":"索赔流程","logoSrc":"","bodyLines":["<Icon icon=''arrowRightToBracket'' /> 通过电子方式接收索赔或由用户批量导入","<Icon icon=''personCircleQuestion'' /> 索赔待人工审核","<Icon icon=''gears'' /> 根据计划设计和配置规则进行索赔裁定","<Icon icon=''moneyCheckDollar'' /> 通过电子转账或支票生成自动处理支付"]},{"id":"impact","title":"影响","logoSrc":"","bodyLines":["<Icon icon=''peopleLine'' /> 数十万份证书轻松加入且配备移动访问","<Icon icon=''hospitalUser'' /> 加拿大各地已注册的医疗保健提供者可提交电子索赔","<Icon icon=''handHoldingDollar'' /> 通过自动化和欺诈检测为保险公司、第三方管理员和计划赞助商带来显著的运营和福利成本节省。"]},{"id":"connect","title":"应用程序","logoSrc":"","bodyLines":[],"isConnectCard":true,"links":[{"label":"TPA网站","handle":"www.adjudicare.net","url":"https://www.adjudicare.net"},{"label":"","handle":"会员网络门户","url":"https://www.onlineclaimsaccess.net"},{"label":"","handle":"会员iOS应用","url":"https://apps.apple.com/ca/app/my-health-benefits/id671060840"},{"label":"","handle":"会员Android应用","url":"https://play.google.com/store/apps/details?id=ca.symbilityhealth.mobileclaims&pli=1"}]}],"artworkHeading":"","artworkBody":"","artworkImageAlts":[],"artworkImageSrcs":[],"creativePostsHeading":"","creativePostsIntro":"","events":[],"creativeReelsHeading":"","creativeReelsBody":"","showcases":[{"heading":"软件工程总监","subtitle":"2018年5月 - 2025年11月 在TELUS","cards":[{"title":"领导力","description":"建立并扩展了50多人的跨职能工程团队，通过敏捷转型、DevOps实践和亲身指导，实现了交付速度60%的改进。"},{"title":"增长","description":"创建了一种高绩效文化，促进协作、技术卓越和全球分布式团队的职业发展。通过战略性客户进入和收购后成功的服务扩展，推动了4倍的收入增长。"},{"title":"执行","description":"领导企业规模的现代化倡议，包括从本地到AWS云迁移、转变为微服务架构和完整UI使用Angular重建——全部按时完成并在范围内交付。"},{"title":"合规","description":"建立强大的安全和隐私实践，确保SOC 2 Type II合规。与毕马威合作进行年度审计，为医疗保健和保险数据保护维持世界级标准。"}]},{"heading":"软件开发副总裁","subtitle":"2004年6月 - 2018年5月 在Symbility Health (被TELUS收购)","cards":[{"title":"保险专业知识","description":"从开发人员晋升为资深领导，掌握全栈软件开发，同时在集体保险管理和健康保险索赔裁定领域建立深厚的领域专业知识。"},{"title":"创新","description":"推动专业药房管理(Biometrx)和患者支持平台的开发，将业务扩展到药学和专业护理部门。"},{"title":"流程卓越","description":"引入敏捷Scrum框架并推动持续流程改进，包括CI/CD流水线和测试自动化，显著提升团队生产力和发布质量。"},{"title":"合规","description":"通过实施和验证所需的安全控制和信息安全管理实践，支持Symbility的ISO 27001认证。"}]}]}]},"specialties":{"pageTitle":"专业领域 | Jason Zhu","title":"健康保险工程","sectionTitle":"改变保险业的新兴技术","intro":"计划成员和医疗保健提供者期望在访问保险信息、提交索赔和接收支付时获得无缝的数字体验。为了满足这些期望，保险公司和第三方管理员(TPA)必须利用新兴技术来现代化其遗留系统和流程。关键技术如AI辅助开发、云计算、微服务架构和API驱动平台正在革新保险解决方案的设计、构建和交付方式。通过采用这些创新，保险公司可以提高运营效率、改善客户满意度，并在竞争激烈的市场中推动业务增长。","roles":[{"title":"具有健康保险领域专业知识的战略技术领导者","organization":"推动可扩展的健康福利管理和索赔裁定平台","duration":"(2012 - 2025)","imageSrc":"/img/{person_id}/specialty_claims_solution.png","imageAlt":"战略技术领导者 - 健康福利管理和裁定系统","link":"engagements#engagement-0"},{"title":"从程序员到首席工程师","organization":"在架构、设计、编码、测试、维护和DevOps方面拥有全栈工程经验","duration":"(1998 - 2025)","imageSrc":"/img/{person_id}/specialty_technology_evolution.png","imageAlt":"市场营销与设计总监 - UofT金融与领导力委员会"}]},"cherish":{"browserTabName":"Cherish Integrated Services - Jason Zhu","hero":{"title":"Cherish Integrated Services","subtitle":"设计慈善活动网站和捐赠平台","cta_label":"访问网站","cta_url":"https://cherish-love-gala-2024.raiselysite.com/"},"organization":{"heading":"组织背景","body":["Cherish Integrated Services(CHIS)是一个非营利组织和注册慈善机构，为大多伦多地区有发育障碍的人士提供服务。他们为每个年龄段提供各种项目，帮助职业培训、工作创业和日常生活。","CHIS主办年度爱情慈善晚宴以筹集资金进一步扩展其服务和设施。今年，收益将用于开发他们的新职业培训中心。这个新设施将帮助更多经过培训的学员在真实的咖啡馆环境中工作并学习可就业的技能。"]},"role":{"heading":"我的角色","title":"数字营销协调员","dates":"2024年6月 - 2024年8月","body":["作为任期内唯一的设计师，我使用Raisley平台为2024年Cherish爱情慈善晚宴活动开发了一个网站。我确保包含了关于该活动的重要细节，并管理了来的捐款和门票销售。","除了设计方面，我还积极参与了赞助商计划的开发，并与当地企业和媒体就该活动进行沟通。"]},"features":{"centerVideo":"/img/{person_id}/cherish_demo.mp4","centerVideoPoster":"/img/{person_id}/cherish_features.avif","centerVideoAlt":"Cherish爱情慈善晚宴网站演示","leftItems":[{"title":"表演者个人资料","description":"为每位表演者创建介绍和捐赠页面，支持者可以向其捐款。"},{"title":"门票销售与捐款","description":"链接Powr.io用于门票销售和税收收据中的食品成本扣除。"}],"rightItems":[{"title":"活动详情","description":"告知客人活动的地点、日期、时间和门票包含内容。描述所有收益将用途的事业。"},{"title":"赞助商","description":"在页脚中列出所有支持者、活动赞助商和奖品(抽奖和无声拍卖)赞助商，并提供返回链接到他们的网站。"}]},"gallery":{"leftImage":{"src":"/img/{person_id}/cherish_performers.avif","alt":"爱情慈善晚宴表演者页面截图"},"middleImages":[{"src":"/img/{person_id}/cherish_donation.avif","alt":"承诺捐赠页面截图"},{"src":"/img/{person_id}/cherish_donation2.avif","alt":"承诺捐赠页面截图2"}],"rightImage":{"src":"/img/{person_id}/cherish_about.avif","alt":"什么是Cherish爱情慈善晚宴页面截图"}}},"simonSaves":{"browserTabName":"SimonSaves - Jason Zhu","hero":{"title":"SimonSaves","subtitle":"Rotman Commerce创新小组 x Rotman Commerce Fintech协会设计冲刺决赛选手","cta_label":"查看原型","cta_url":"https://www.figma.com/proto/xw4hyc3g8zxUA3be71XRB2/Recipe-Book-App-Prototype?type=design&node-id=1-2&t=hYJdCZQe1uISo0eg-1&scaling=scale-down&page-id=0%3A1&starting-point-node-id=180%3A223"},"overview":{"heading":"概述","body":["我们的4人小组在一个案例竞赛中排名前三，该竞赛要求我们为金融科技领域的问题设计解决方案。我们的解决方案引入了一个应用程序，使用机器学习根据用户的预算和饮食限制及偏好推荐食谱和餐食消费。"]},"keyFeatures":{"title":"主要特性","items":["基于饮食限制和建议的过滤食谱和杂货搜索","主页上的财务食品预算摘要","提供不同成分提示和事实的信息卡","与其他应用用户聊天和提问的在线社区","主页上的滚动广告横幅，促进持续的折扣和销售"]},"role":{"heading":"我的角色","title":"UX设计师和logo创建者","dates":"2023","body":["由于我通过Google在线UX设计课程使用Figma的经验，与另一个团队成员一起，我们承担了为财务预算和食品教育开发用户友好应用的任务。我们团队的多样化技能使我能够领导设计流程并指导我的队友了解Figma的基本功能。","我们一起制作了纸质线框来进行头脑风暴，然后为应用的每一页创建了模型。然后我承担了原型阶段的唯一责任，确保所有按钮的无缝交互。","由于我丰富的视觉艺术背景，我也承担了为我们的品牌创建个性化吉祥物和标志的任务。我们的预期品牌形象是教育性和友好的，因此创造了Simon the Persimmon。作为一个小组，我们决定了这个名称，因为我们相信消费者会立即将独特的水果与我们的品牌联系起来，因为它的押韵名称和不常见的用途。"]},"results":{"heading":"结果","body":["我们的小组进入了最终演讲轮，我们有机会向经验丰富的UX和产品设计师小组介绍我们的想法。最终演讲包括10分钟的演讲交付和5分钟的小组成员问答。"]},"learnings":{"title":"学习","items":["设计过程是一个持续的循环","技术背景知识至关重要","利用团队成员的多样化技能进行任务委派，但确保所有成员在项目的每个方面都有发言权以最大化潜力"]},"gallery":{"mainImage":{"src":"/img/{person_id}/SimonSaves_Mockup.avif","alt":"SimonSaves应用模型截图"},"mascotImage":{"src":"/img/{person_id}/SimonSaves_Logo.avif","alt":"Simon the Persimmon吉祥物logo"}}}}',
  NOW()
)
ON CONFLICT ("PortfolioId", "Language") DO NOTHING;

